body.script:
// ═══════════════════════════════
// DATA
// ═══════════════════════════════
const PAIRS=['BTC/USDT','ETH/USDT','SOL/USDT','BNB/USDT','XRP/USDT','DOGE/USDT','ADA/USDT','AVAX/USDT','LINK/USDT','DOT/USDT','MATIC/USDT','LTC/USDT','NEAR/USDT','APT/USDT','ARB/USDT','OP/USDT','INJ/USDT','SUI/USDT','TIA/USDT','WIF/USDT'];

// ─── BALANCES (USDT disponível por exchange/tipo) ───
// Em produção esses valores viriam das APIs das corretoras via REST/WS
const BALANCES = {
  BingX:  { spot: 2341.50, futures: 1850.00 },
  MEXC:   { spot: 1920.00, futures: 3100.00 },
  Gate:   { spot:  890.75, futures: 2450.00 },
  KuCoin: { spot:    0.00, futures:    0.00 }, // desconectado
};

// Tipo do saldo a usar por modalidade ARB
function balType(arbType, side){
  // SS: ambos spot | FF: ambos futures | SF: buy=spot sell=futures
  if(arbType==='SS') return 'spot';
  if(arbType==='FF') return 'futures';
  return side==='buy' ? 'spot' : 'futures';
}

function getAvailBuy(){
  const r=filteredRows[selIdx]; if(!r) return 0;
  const exch=document.getElementById('buyEx').value;
  const t=balType(r.type,'buy');
  return BALANCES[exch]?.[t]||0;
}
function getAvailSell(){
  const r=filteredRows[selIdx]; if(!r) return 0;
  const exch=document.getElementById('sellEx').value;
  const t=balType(r.type,'sell');
  return BALANCES[exch]?.[t]||0;
}
function getMaxQty(){
  return Math.min(getAvailBuy(), getAvailSell());
}

let qtyPct=100;
const EXCHS=['BingX','MEXC','Gate','KuCoin'];
const TYPES=['SS','SF','FF'];
const FEE={BingX:.075,MEXC:.020,Gate:.060,KuCoin:.100};
let allRows=[],filteredRows=[],selIdx=0,apfType='all',pctVal=100;

let positions=[
  {sym:'ETH/USDT',side:'LONG',type:'SF',entry:2341.20,cur:2389.50,qty:500,bEx:'BingX',sEx:'MEXC',bOid:'b_001',sOid:'s_001'},
  {sym:'SOL/USDT',side:'SHORT',type:'FF',entry:98.40,cur:96.10,qty:200,bEx:'Gate',sEx:'KuCoin',bOid:'b_002',sOid:'s_002'},
  {sym:'BNB/USDT',side:'LONG',type:'SS',entry:312.50,cur:315.80,qty:300,bEx:'MEXC',sEx:'BingX',bOid:'b_003',sOid:'s_003'},
];

// Trade history — pre-populated for demonstration
const tradeHistory = generateHistory();

function generateHistory(){
  const hist=[];
  const now=Date.now();
  const syms=['BTC/USDT','ETH/USDT','SOL/USDT','BNB/USDT','XRP/USDT','DOGE/USDT','AVAX/USDT','LINK/USDT'];
  const ex1=['BingX','MEXC','Gate'];
  const ex2=['MEXC','Gate','KuCoin'];
  for(let i=60;i>=0;i--){
    const t=TYPES[Math.floor(Math.random()*3)];
    const sym=syms[Math.floor(Math.random()*syms.length)];
    const bEx=ex1[Math.floor(Math.random()*ex1.length)];
    const sEx=ex2[Math.floor(Math.random()*ex2.length)];
    const buyP=100+Math.random()*60000;
    const spread=+(0.2+Math.random()*2).toFixed(3);
    const sellP=+(buyP*(1+spread/100)).toFixed(2);
    const fees=+(FEE[bEx]+FEE[sEx]).toFixed(3);
    const slip=+(Math.random()*.08).toFixed(3);
    const pnlPct=+(spread-fees-slip).toFixed(3);
    const qty=Math.round((200+Math.random()*800)/50)*50;
    const pnlUsd=+(pnlPct/100*qty).toFixed(2);
    const ts=new Date(now-(i*23*60*60*1000+Math.random()*20*60*60*1000));
    const status=Math.random()>.05?'closed':Math.random()>.5?'cancelled':'open';
    const isWin=pnlPct>0;
    hist.push({id:60-i,ts,sym,type:t,bEx,sEx,buyP:+buyP.toFixed(2),sellP,spread,fees,slip,pnlPct:status==='cancelled'?0:pnlPct,pnlUsd:status==='cancelled'?0:pnlUsd,qty,status,isWin:status==='closed'&&isWin});
  }
  return hist;
}

function shuffle(a){for(let i=a.length-1;i>0;i--){const j=Math.floor(Math.random()*(i+1));[a[i],a[j]]=[a[j],a[i]]}return a}
function fmt(n){return n>=1e6?(n/1e6).toFixed(1)+'M':n>=1e3?(n/1e3).toFixed(0)+'K':''+n}
function fmtP(p,r=1){return p>1000?'$'+p.toLocaleString('en',{maximumFractionDigits:r}):'$'+p.toFixed(4)}
function fmtDate(d){return d.toLocaleDateString('pt-BR')+' '+d.toTimeString().slice(0,8)}

// ═══════════════════════════════
// PAGE ROUTING
// ═══════════════════════════════
function switchPage(id,el){
  document.querySelectorAll('.page').forEach(p=>p.classList.remove('on'));
  document.getElementById('pg'+id.charAt(0).toUpperCase()+id.slice(1)).classList.add('on');
  document.querySelectorAll('.gtab').forEach(t=>t.className='gtab');
  el.classList.add('on'+(id==='api'?'-api':id==='results'?'-res':''));
  if(id==='results'){renderOverview();renderOrders();renderDaily()}
}

function switchRes(id,el){
  document.querySelectorAll('.res-subpage').forEach(p=>p.classList.remove('on'));
  document.getElementById('res-'+id).classList.add('on');
  document.querySelectorAll('.res-tab').forEach(t=>t.classList.remove('on'));
  el.classList.add('on');
}

// ═══════════════════════════════
// RESULTS: OVERVIEW
// ═══════════════════════════════
function renderOverview(){
  const closed=tradeHistory.filter(t=>t.status==='closed');
  const wins=closed.filter(t=>t.isWin);
  const losses=closed.filter(t=>!t.isWin);
  const totalPnlUsd=closed.reduce((s,t)=>s+t.pnlUsd,0);
  const totalPnlPct=closed.reduce((s,t)=>s+t.pnlPct,0);
  const winRate=closed.length?((wins.length/closed.length)*100).toFixed(1):0;
  const avgWin=wins.length?(wins.reduce((s,t)=>s+t.pnlUsd,0)/wins.length).toFixed(2):0;
  const avgLoss=losses.length?(Math.abs(losses.reduce((s,t)=>s+t.pnlUsd,0)/losses.length)).toFixed(2):0;
  const bestTrade=closed.reduce((a,b)=>a.pnlUsd>b.pnlUsd?a:b,{pnlUsd:-Infinity});
  const worstTrade=closed.reduce((a,b)=>a.pnlUsds+t.fees/100*t.qty,0).toFixed(2);

  document.getElementById('resBanner').innerHTML=`


PnL Total USDT
${totalPnlUsd>=0?'+':''}$${totalPnlUsd.toFixed(2)}
${closed.length} trades fechados


PnL Total %
${totalPnlPct>=0?'+':''}${totalPnlPct.toFixed(3)}%
acumulado do período


Win Rate
${winRate}%
${wins.length} wins / ${losses.length} losses


Avg Win
+$${avgWin}
por trade lucrativo


Avg Loss
-$${avgLoss}
por trade negativo


Melhor Trade
+$${bestTrade.pnlUsd||0}
${bestTrade.sym||'—'}


Pior Trade
${worstTrade.pnlUsd!==Infinity?'$'+worstTrade.pnlUsd:'—'}
${worstTrade.sym||'—'}


Total Taxas Pagas
-$${totalFees}
todas as exchanges


Total Trades
${tradeHistory.length}
${tradeHistory.filter(t=>t.status==='open').length} abertos agora
  `;
  document.getElementById('ordBadge').textContent=closed.length;

  // Charts
  const chartRow=document.getElementById('resCharts');
  chartRow.innerHTML=`


📈 PnL Acumulado (USDT)


🍕 Win / Loss Ratio


📊 Trades por Tipo ARB
  `;
  setTimeout(()=>{
    drawPnlLine(closed);
    drawPie(wins.length,losses.length);
    drawTypeBar();
  },50);
}

function drawPnlLine(trades){
  const c=document.getElementById('cPnl');if(!c)return;
  const W=c.offsetWidth||400,H=90;c.width=W;c.height=H;
  const ctx=c.getContext('2d');ctx.clearRect(0,0,W,H);
  let cum=0;
  const pts=trades.map((t,i)=>{cum+=t.pnlUsd;return[i,cum]});
  if(pts.length<2)return;
  const minY=Math.min(...pts.map(p=>p[1]));
  const maxY=Math.max(...pts.map(p=>p[1]));
  const rng=maxY-minY||1;
  const px=(i)=>8+(W-16)*i/(pts.length-1);
  const py=(v)=>H-8-(v-minY)/rng*(H-16);
  const color=cum>=0?'#00ff87':'#ff2d55';
  const grad=ctx.createLinearGradient(0,8,0,H);
  grad.addColorStop(0,color+'55');grad.addColorStop(1,color+'00');
  ctx.beginPath();
  pts.forEach((p,i)=>i?ctx.lineTo(px(i),py(p[1])):ctx.moveTo(px(i),py(p[1])));
  ctx.lineTo(px(pts.length-1),H);ctx.lineTo(px(0),H);ctx.closePath();
  ctx.fillStyle=grad;ctx.fill();
  ctx.beginPath();
  pts.forEach((p,i)=>i?ctx.lineTo(px(i),py(p[1])):ctx.moveTo(px(i),py(p[1])));
  ctx.strokeStyle=color;ctx.lineWidth=1.5;ctx.stroke();
  // Zero line
  if(minY<0&&maxY>0){
    const zy=py(0);
    ctx.beginPath();ctx.moveTo(8,zy);ctx.lineTo(W-8,zy);
    ctx.strokeStyle='#334155';ctx.lineWidth=0.5;ctx.setLineDash([3,3]);ctx.stroke();ctx.setLineDash([]);
  }
}

function drawPie(wins,losses){
  const c=document.getElementById('cPie');if(!c)return;
  const S=90;c.width=S;c.height=S;
  const ctx=c.getContext('2d');
  const tot=wins+losses||1;
  const wa=(wins/tot)*Math.PI*2;
  const cx=S/2,cy=S/2,r=36;
  ctx.beginPath();ctx.moveTo(cx,cy);ctx.arc(cx,cy,r,-.5*Math.PI,-.5*Math.PI+wa);ctx.closePath();
  ctx.fillStyle='#00ff87';ctx.fill();
  ctx.beginPath();ctx.moveTo(cx,cy);ctx.arc(cx,cy,r,-.5*Math.PI+wa,-.5*Math.PI+Math.PI*2);ctx.closePath();
  ctx.fillStyle='#ff2d55';ctx.fill();
  ctx.fillStyle='#03050800';ctx.beginPath();ctx.arc(cx,cy,20,0,Math.PI*2);ctx.fill();
  ctx.fillStyle='#030508';ctx.beginPath();ctx.arc(cx,cy,20,0,Math.PI*2);ctx.fill();
  ctx.fillStyle='#e2e8f0';ctx.font='bold 11px Syne,sans-serif';ctx.textAlign='center';ctx.textBaseline='middle';
  ctx.fillText(((wins/tot)*100).toFixed(0)+'%',cx,cy);
}

function drawTypeBar(){
  const c=document.getElementById('cType');if(!c)return;
  const W=c.offsetWidth||180,H=90;c.width=W;c.height=H;
  const ctx=c.getContext('2d');ctx.clearRect(0,0,W,H);
  const closed=tradeHistory.filter(t=>t.status==='closed');
  const byType={SS:closed.filter(t=>t.type==='SS').length,SF:closed.filter(t=>t.type==='SF').length,FF:closed.filter(t=>t.type==='FF').length};
  const colors={SS:'#0088ff',SF:'#ffcc00',FF:'#00e5ff'};
  const max=Math.max(...Object.values(byType))||1;
  const keys=Object.keys(byType);
  const bw=(W-16)/keys.length-8;
  keys.forEach((k,i)=>{
    const bh=(byType[k]/max)*(H-24);
    const x=8+i*(bw+8);const y=H-12-bh;
    ctx.fillStyle=colors[k]+'44';ctx.fillRect(x,y,bw,bh);
    ctx.fillStyle=colors[k];ctx.fillRect(x,y,bw,3);
    ctx.fillStyle='#94a3b8';ctx.font='8px JetBrains Mono,monospace';ctx.textAlign='center';
    ctx.fillText(k,x+bw/2,H-3);
    ctx.fillStyle='#e2e8f0';ctx.font='bold 10px JetBrains Mono,monospace';
    ctx.fillText(byType[k],x+bw/2,y-4);
  });
}

// ═══════════════════════════════
// RESULTS: ORDERS TABLE
// ═══════════════════════════════
function renderOrders(){
  const status=document.getElementById('ordStatus').value;
  const type=document.getElementById('ordType2').value;
  const result=document.getElementById('ordResult').value;
  const exch=document.getElementById('ordExch').value;
  const sym=(document.getElementById('ordSym').value||'').toUpperCase();
  let rows=tradeHistory.filter(t=>{
    if(status!=='all'&&t.status!==status)return false;
    if(type!=='all'&&t.type!==type)return false;
    if(result==='win'&&!t.isWin)return false;
    if(result==='loss'&&(t.isWin||t.status!=='closed'))return false;
    if(exch!=='all'&&t.bEx!==exch&&t.sEx!==exch)return false;
    if(sym&&!t.sym.includes(sym))return false;
    return true;
  }).sort((a,b)=>b.ts-a.ts);
  document.getElementById('ordTotal').textContent=rows.length;
  document.getElementById('ordBody').innerHTML=rows.map(t=>{
    const pC=t.pnlPct>=0?'o-win':'o-loss';
    const uC=t.pnlUsd>=0?'o-win':'o-loss';
    const sTag=t.status==='closed'?`FECHADO`:t.status==='open'?`ABERTO`:`CANCELADO`;
    return`

      ${t.id}
      ${fmtDate(t.ts)}
      ${t.sym}
      ${t.type}
      ${t.bEx}
      ${t.sEx}
      ${fmtP(t.buyP,2)}
      ${fmtP(t.sellP,2)}
      $${t.qty}
      ${t.spread.toFixed(3)}%
      -${t.fees.toFixed(3)}%
      -${t.slip.toFixed(3)}%
      ${t.status==='cancelled'?'—':(t.pnlPct>=0?'+':'')+t.pnlPct.toFixed(3)+'%'}
      ${t.status==='cancelled'?'—':(t.pnlUsd>=0?'+$':'-$')+Math.abs(t.pnlUsd).toFixed(2)}
      ${sTag}
    `;
  }).join('');
}

function exportOrders(){
  notify('⬇ Exportando CSV...','c');
}

// ═══════════════════════════════
// RESULTS: DAILY SUMMARY
// ═══════════════════════════════
function renderDaily(){
  const byDay={};
  tradeHistory.forEach(t=>{
    const d=t.ts.toLocaleDateString('pt-BR');
    if(!byDay[d])byDay[d]={date:d,trades:0,wins:0,losses:0,pnlUsd:0,pnlPct:0,fees:0,vol:0};
    const day=byDay[d];
    day.trades++;
    if(t.status==='closed'){
      if(t.isWin)day.wins++;else day.losses++;
      day.pnlUsd+=t.pnlUsd;
      day.pnlPct+=t.pnlPct;
      day.fees+=t.fees/100*t.qty;
    }
    day.vol+=t.qty;
  });
  const days=Object.values(byDay).reverse();
  document.getElementById('dailyGrid').innerHTML=days.map(d=>{
    const isGreen=d.pnlUsd>=0;
    const wr=d.trades?((d.wins/d.trades)*100).toFixed(0):0;
    const winW=d.trades?Math.round(d.wins/d.trades*100):0;
    return`



        ${d.date}
        ${isGreen?'+':''}$${d.pnlUsd.toFixed(2)}




PnL %${isGreen?'+':''}${d.pnlPct.toFixed(3)}%

Trades${d.trades}

Win Rate${wr}%

Wins / Losses${d.wins} ✓ / ${d.losses} ✗

Volume$${fmt(d.vol)}

Taxas pagas-$${d.fees.toFixed(2)}








    `;
  }).join('');
}

// ═══════════════════════════════
// API KEYS
// ═══════════════════════════════
function toggleEye(id,btn){
  const inp=document.getElementById(id);
  if(inp.type==='password'){inp.type='text';btn.textContent='🙈'}
  else{inp.type='password';btn.textContent='👁'}
}

function testApi(exch){
  const dot=document.getElementById(exch+'-dot');
  const stat=document.getElementById(exch+'-status');
  dot.className='api-status-dot ld-warn';
  stat.textContent='Testando...';stat.style.color='var(--yellow)';
  notify(`🔌 Testando conexão ${exch}...`,'');
  setTimeout(()=>{
    const ok=exch!=='kucoin'||Math.random()>.3;
    dot.className='api-status-dot '+(ok?'on':'err');
    stat.textContent=ok?'Conectado':'Erro de conexão';
    stat.style.color=ok?'var(--green)':'var(--red)';
    notify(ok?`✓ ${exch} conectado com sucesso!`:`✗ ${exch} falhou — verifique a key`,'e');
    if(ok){
      const inp=document.getElementById(exch+'-key');
      if(inp&&inp.value)inp.className='api-inp valid';
    }
  },1500);
}

function saveApi(exch){
  const key=document.getElementById(exch+'-key')?.value;
  const secret=document.getElementById(exch+'-secret')?.value;
  if(!key||!secret){notify(`⚠ Preencha Key e Secret do ${exch}`,'w');return}
  // In production: encrypt and save to localStorage/server
  notify(`💾 ${exch} API Key salva localmente`,'p');
}

// ═══════════════════════════════
// BALANCE PANEL + QTY SELECTOR
// ═══════════════════════════════
function updateBalPanel(){
  const r=filteredRows[selIdx];
  const buyExch=document.getElementById('buyEx').value;
  const sellExch=document.getElementById('sellEx').value;
  const arbType=r?r.type:'SF';

  const bType=balType(arbType,'buy');
  const sType=balType(arbType,'sell');

  const bBal=BALANCES[buyExch]?.[bType]||0;
  const sBal=BALANCES[sellExch]?.[sType]||0;
  const price=r?r.buyAt:1;
  const sym=r?r.sym.split('/')[0]:'—';

  // Update labels
  document.getElementById('balBuyName').textContent=buyExch;
  document.getElementById('balBuyType').textContent=bType.toUpperCase();
  document.getElementById('balSellName').textContent=sellExch;
  document.getElementById('balSellType').textContent=sType.toUpperCase();

  // Buy side
  const bEl=document.getElementById('balBuyUsdt');
  bEl.textContent='$'+bBal.toLocaleString('en',{minimumFractionDigits:2,maximumFractionDigits:2});
  bEl.className='bal-avail'+(bBal<100?' empty':bBal<500?' low':'');
  document.getElementById('balBuyAsset').textContent='≈ '+(bBal/price).toFixed(4)+' '+sym+' disp.';

  // Sell side
  const sEl=document.getElementById('balSellUsdt');
  sEl.textContent='$'+sBal.toLocaleString('en',{minimumFractionDigits:2,maximumFractionDigits:2});
  sEl.className='bal-avail'+(sBal<100?' empty':sBal<500?' low':'');
  document.getElementById('balSellAsset').textContent='≈ '+(sBal/price).toFixed(4)+' '+sym+' disp.';

  // Set qty to current pct of max
  applyQtyPct(qtyPct);
}

function applyQtyPct(pct){
  qtyPct=pct;
  const maxQ=getMaxQty();
  const qty=Math.floor(maxQ*pct/100);
  document.getElementById('qty').value=qty;
  updateQtyDisplay(qty);
}

function setQtyPct(pct,el){
  if(el){document.querySelectorAll('.qpb').forEach(b=>b.classList.remove('on'));el.classList.add('on');}
  applyQtyPct(pct);
}

function onQtyInput(){
  // When user manually types, unselect pct buttons
  document.querySelectorAll('.qpb').forEach(b=>b.classList.remove('on'));
  const v=parseFloat(document.getElementById('qty').value)||0;
  updateQtyDisplay(v);
}

function updateQtyDisplay(qty){
  const r=filteredRows[selIdx];
  const price=r?r.buyAt:1;
  const sym=r?r.sym.split('/')[0]:'—';
  const maxQ=getMaxQty();
  const bBal=getAvailBuy(), sBal=getAvailSell();

  document.getElementById('qtyResUsdt').textContent='$'+qty.toLocaleString('en',{maximumFractionDigits:0});
  document.getElementById('qtyResAsset').textContent=(qty/price).toFixed(5)+' '+sym;

  const insuf=qty>bBal||qty>sBal;
  document.getElementById('qtyInsuf').className='qty-insuf'+(insuf?' show':'');

  // Also update cost calc
  if(r){
    const f1=FEE[r.exchs[0]]||.075,f2=FEE[r.exchs[1]]||.020;
    const fr=Math.abs(r.fr),sl=.05;
    const net=r.spread-f1-f2-fr*100-sl;
    const nEl=document.getElementById('cNet');
    nEl.textContent=(net>0?'+':'')+net.toFixed(3)+'%';
    nEl.style.color=net>0?'var(--green)':'var(--red)';
    document.getElementById('cUsd').textContent=(net>0?'+$':'-$')+Math.abs(net/100*qty).toFixed(2);
  }
}

function useMaxBuy(){
  const v=getAvailBuy();
  const capped=Math.min(v,getAvailSell());
  document.getElementById('qty').value=Math.floor(capped);
  document.querySelectorAll('.qpb').forEach(b=>b.classList.remove('on'));
  const lastPcb=document.querySelectorAll('.qpb');
  if(lastPcb.length) lastPcb[lastPcb.length-1].classList.add('on');
  updateQtyDisplay(Math.floor(capped));
}

function useMaxSell(){
  const v=getAvailSell();
  const capped=Math.min(v,getAvailBuy());
  document.getElementById('qty').value=Math.floor(capped);
  document.querySelectorAll('.qpb').forEach(b=>b.classList.remove('on'));
  const lastPcb=document.querySelectorAll('.qpb');
  if(lastPcb.length) lastPcb[lastPcb.length-1].classList.add('on');
  updateQtyDisplay(Math.floor(capped));
}

function onExchChange(){
  const r=filteredRows[selIdx];if(!r)return;
  updateBalPanel();
  const f1=FEE[document.getElementById('buyEx').value]||.075;
  const f2=FEE[document.getElementById('sellEx').value]||.020;
  document.getElementById('cF1').textContent='-'+f1.toFixed(3)+'%';
  document.getElementById('cF2').textContent='-'+f2.toFixed(3)+'%';
  const fr=Math.abs(r.fr),sl=.05;
  const net=r.spread-f1-f2-fr*100-sl;
  const nEl=document.getElementById('cNet');
  nEl.textContent=(net>0?'+':'')+net.toFixed(3)+'%';
  nEl.style.color=net>0?'var(--green)':'var(--red)';
  const qty=parseFloat(document.getElementById('qty').value)||0;
  document.getElementById('cUsd').textContent=(net>0?'+$':'-$')+Math.abs(net/100*qty).toFixed(2);
}

// Simulate balance fluctuation (in production: pull from API)
function liveBalances(){
  Object.keys(BALANCES).forEach(ex=>{
    BALANCES[ex].spot=Math.max(0,BALANCES[ex].spot+(Math.random()-.5)*20);
    BALANCES[ex].futures=Math.max(0,BALANCES[ex].futures+(Math.random()-.5)*30);
  });
}

// ═══════════════════════════════
// SCANNER DATA
// ═══════════════════════════════
function genRows(){
  allRows=[];
  for(let i=0;ib.spread-a.spread);
  allRows.forEach((r,i)=>r.rank=i+1);
}

function renderAsset(){
  const srch=(document.getElementById('apSrch').value||'').toUpperCase();
  let rows=filteredRows.filter(r=>{
    if(apfType!=='all'&&r.type!==apfType)return false;
    if(srch&&!r.sym.includes(srch))return false;
    return true;
  });
  document.getElementById('listCt').textContent=rows.length;
  document.getElementById('minSV').textContent=(document.getElementById('fSp').value||'0.3')+'%';
  document.getElementById('alist').innerHTML=rows.map(r=>{
    const fi=filteredRows.indexOf(r);
    const sc=r.spread>1.5?'h':r.spread>0.6?'w':'c';
    return`

      ${r.sym}
      ${r.spread.toFixed(2)}%
      ${r.type}
    `;
  }).join('');
}

function apf(type,el){
  apfType=type;
  document.querySelectorAll('.ftag').forEach(b=>b.classList.remove('on'));
  el.classList.add('on');
  renderAsset();
}

function renderScanner(){
  document.getElementById('oppCnt').textContent=filteredRows.filter(r=>r.spread>.5).length;
  document.getElementById('scanBadge').textContent=filteredRows.filter(r=>r.net>0).length;
  document.getElementById('scBody').innerHTML=filteredRows.map((r,i)=>{
    const sc=r.spread>1.5?'h':r.spread>0.6?'w':'c';
    const fc=r.fr>=0?'sr-fp':'sr-fn';
    return`

      ${r.rank}
      ${r.sym}
      ${r.type}
      ${r.exchs.map(e=>`${e}`).join('')}
      ${r.spread.toFixed(3)}%
      ${fmtP(r.buyAt,1)}
      ${fmtP(r.sellAt,1)}
      ${r.fr>=0?'+':''}${r.fr.toFixed(3)}%

${fmt(r.liq)}
      ${r.net>0?'+':''}${r.net.toFixed(2)}%

        ⚡ARB
        👁

    `;
  }).join('');
}

function sel(idx){
  selIdx=idx;
  const r=filteredRows[idx];if(!r)return;
  document.getElementById('phSym').textContent=r.sym;
  document.getElementById('phSp').textContent=r.spread.toFixed(3)+'%';
  document.getElementById('phType').className='at t'+r.type.toLowerCase();
  document.getElementById('phType').textContent=r.type;
  const nEl=document.getElementById('phNet');
  nEl.textContent=(r.net>0?'+':'')+r.net.toFixed(2)+'%';
  nEl.style.color=r.net>0?'var(--green)':'var(--red)';
  document.getElementById('phBE').textContent=r.exchs[0];
  document.getElementById('phSE').textContent=r.exchs[1];
  document.getElementById('obBE').textContent=r.exchs[0];
  document.getElementById('obSE').textContent=r.exchs[1];
  document.getElementById('qePair').textContent=r.sym;
  document.getElementById('lBuy').value=r.buyAt;
  document.getElementById('lSell').value=r.sellAt;
  document.getElementById('buyEx').value=r.exchs[0];
  document.getElementById('sellEx').value=r.exchs[1];
  updateBalPanel();
  const f1=FEE[r.exchs[0]]||.075,f2=FEE[r.exchs[1]]||.020;
  const fr=Math.abs(r.fr),sl=.05;
  const net=r.spread-f1-f2-fr*100-sl;
  const qty=parseFloat(document.getElementById('qty').value)||getMaxQty()||500;
  document.getElementById('cSp').textContent='+'+r.spread.toFixed(3)+'%';
  document.getElementById('cF1').textContent='-'+f1.toFixed(3)+'%';
  document.getElementById('cF2').textContent='-'+f2.toFixed(3)+'%';
  document.getElementById('cFr').textContent='-'+fr.toFixed(3)+'%';
  document.getElementById('cSl').textContent='-'+sl.toFixed(3)+'%';
  const nEl2=document.getElementById('cNet');
  nEl2.textContent=(net>0?'+':'')+net.toFixed(3)+'%';
  nEl2.style.color=net>0?'var(--green)':'var(--red)';
  document.getElementById('cUsd').textContent=(net>0?'+$':'-$')+Math.abs(net/100*qty).toFixed(2);
  renderOB(r.buyAt,r.liq);
  renderScanner();renderAsset();
}

function renderOB(mid,liq){
  const asks=[],bids=[];let al=0,bl=0;
  for(let i=5;i>0;i--){const p=mid*(1+i*.00030);const q=+(0.5+Math.random()*10).toFixed(3);asks.push([p,q,p*q]);al+=p*q}
  for(let i=1;i<=5;i++){const p=mid*(1-i*.00030);const q=+(0.5+Math.random()*10).toFixed(3);bids.push([p,q,p*q]);bl+=p*q}
  const ma=Math.max(...asks.map(a=>a[2])),mb=Math.max(...bids.map(b=>b[2]));
  document.getElementById('obAsks').innerHTML=asks.map(a=>`

${fmtP(a[0],1)}${a[1]}`).join('');
  document.getElementById('obBids').innerHTML=bids.map(b=>`

${fmtP(b[0],1)}${b[1]}`).join('');
  document.getElementById('obSpD').textContent='$'+(mid*0.00060).toFixed(mid>1000?0:4);
  document.getElementById('obLB').textContent='$'+fmt(al);
  document.getElementById('obLS').textContent='$'+fmt(bl);
}

function renderPos(){
  const tbody=document.getElementById('ptBody');
  document.getElementById('psCt').textContent=positions.length+' ativas';
  document.getElementById('posCount').textContent=positions.length;
  if(!positions.length){tbody.innerHTML=`
Nenhuma posição aberta`;return}
  tbody.innerHTML=positions.map((p,i)=>{
    const pnl=p.side==='LONG'?(p.cur-p.entry)/p.entry*p.qty:(p.entry-p.cur)/p.entry*p.qty;
    const pp=p.side==='LONG'?(p.cur-p.entry)/p.entry*100:(p.entry-p.cur)/p.entry*100;
    return`

      ${p.sym}
      ${p.type}
      ${p.side}
      $${p.entry.toFixed(2)}$${p.cur.toFixed(2)}
      $${p.qty}
      ${pnl>=0?'+':''}$${Math.abs(pnl).toFixed(2)}
      ${pp>=0?'+':''}${pp.toFixed(2)}%
      ${p.bEx}${p.sEx}

        ✕ MKT
        ✕ ORD

    `;
  }).join('');
}

function closeP(i){const p=positions[i];notify(`✕ ${p.sym} fechado MARKET`,'w');positions.splice(i,1);renderPos()}
function cancelP(i){const p=positions[i];notify(`✕ Ordens ${p.sym} canceladas`,'w');positions.splice(i,1);renderPos()}
function cancelAll(){notify('✕ Todas as ordens canceladas','w');positions=[];renderPos()}

function setPct(v,el){pctVal=v;document.querySelectorAll('.qpct').forEach(b=>b.classList.remove('on'));el.classList.add('on')}

function qClose(side){
  const r=filteredRows[selIdx];if(!r){notify('Nenhum par selecionado','w');return}
  const q=parseFloat(document.getElementById('qty').value)||500;
  const cq=(q*pctVal/100).toFixed(0);
  if(side==='buy'||side==='both') notify(`✕ FECHAR BUY ${r.sym} — ${pctVal}% ($${cq}) MARKET @ ${r.exchs[0]}`,'w');
  if(side==='sell'||side==='both') notify(`✕ FECHAR SELL ${r.sym} — ${pctVal}% ($${cq}) MARKET @ ${r.exchs[1]}`,'w');
}

function openExit(){
  if(!positions.length){notify('Nenhuma posição aberta','w');return}
  const bd=document.getElementById('exBd');
  bd.innerHTML=positions.map((p,i)=>{
    const pnl=p.side==='LONG'?(p.cur-p.entry)/p.entry*p.qty:(p.entry-p.cur)/p.entry*p.qty;
    return`


${p.sym}${p.type} | ${p.bEx}→${p.sEx} | $${p.qty}
      ${pnl>=0?'+':''}$${Math.abs(pnl).toFixed(2)}


        50%
        ✕ MKT

    `;
  }).join('')+`

    🔴 FECHAR TUDO — MARKET
    Cancelar
  `;
  document.getElementById('exitModal').classList.add('open');
}

function reRenderExit(){if(positions.length)openExit();else closeExit()}
function closeAll(){closeExit();notify('🔴 TODAS AS POSIÇÕES FECHADAS — MARKET','e');positions=[];renderPos()}
function closeExit(){document.getElementById('exitModal').classList.remove('open')}

function doArb(){
  const r=filteredRows[selIdx];if(!r)return;
  document.getElementById('mPair').textContent=r.sym;
  document.getElementById('mBuy').textContent=`${document.getElementById('buyEx').value} @ $${document.getElementById('lBuy').value}`;
  document.getElementById('mSell').textContent=`${document.getElementById('sellEx').value} @ $${document.getElementById('lSell').value}`;
  document.getElementById('mQty').textContent='$'+document.getElementById('qty').value+' USDT';
  document.getElementById('mSp').textContent=r.spread.toFixed(3)+'%';
  const q=parseFloat(document.getElementById('qty').value)||500;
  document.getElementById('mNet').textContent='+$'+(r.net/100*q).toFixed(2);
  document.getElementById('modal').classList.add('open');
}

function closeM(){document.getElementById('modal').classList.remove('open')}

function confirmArb(){
  closeM();
  const r=filteredRows[selIdx];
  const bex=document.getElementById('buyEx').value;
  const sex=document.getElementById('sellEx').value;
  const q=document.getElementById('qty').value;
  notify(`⚡ ARB ${r.sym} LIMIT BUY@${bex} + SELL@${sex} enviado!`,'');
  positions.push({sym:r.sym,side:'LONG',type:r.type,entry:r.buyAt,cur:r.buyAt,qty:parseFloat(q),bEx:bex,sEx:sex,bOid:'b_'+Date.now(),sOid:'s_'+Date.now()});
  renderPos();
}

function qArb(i){sel(i);doArb()}
function placeLeg(side){const r=filteredRows[selIdx];if(!r)return;notify(side==='buy'?'▲ LIMIT BUY enviado':'▼ LIMIT SELL enviado','')}
function watchRow(i){notify(`👁 ${filteredRows[i].sym} monitorado`,'')}

function applyF(){
  const type=document.getElementById('fType').value;
  const minSp=parseFloat(document.getElementById('fSp').value)||0;
  const minL=parseFloat(document.getElementById('fLiq').value)||0;
  const ex=document.getElementById('fEx').value;
  const srch=(document.getElementById('fSym').value||'').toUpperCase();
  filteredRows=allRows.filter(r=>{
    if(type!=='all'&&r.type!==type)return false;
    if(r.spread<minSp)return false;
    if(r.liq=filteredRows.length)selIdx=0;
  renderScanner();renderAsset();
}

function sortSp(){filteredRows.sort((a,b)=>b.spread-a.spread);renderScanner();renderAsset()}
function refresh(){genRows();applyF();notify('↺ Scanner atualizado','')}

function startBot(){notify('▶ Bot ATIVO','')}
function stopBot(){notify('⏹ Bot PAUSADO','w')}

function notify(msg,type=''){
  const el=document.createElement('div');
  el.className='ni'+(type==='e'?' e':type==='w'?' w':type==='p'?' p':type==='c'?' c':'');
  el.textContent=msg;
  document.getElementById('notif').appendChild(el);
  setTimeout(()=>el.remove(),3200);
}

function live(){
  allRows.forEach(r=>{
    r.spread=Math.max(.05,r.spread+(Math.random()-.5)*.12);
    r.spread=+r.spread.toFixed(3);
    r.net=+(r.spread-r.fees*100-.05).toFixed(3);
    r.fr+=((Math.random()-.5)*.001);r.fr=+r.fr.toFixed(4);
    r.liq+=((Math.random()-.5)*15000);r.liq=Math.max(10000,+r.liq.toFixed(0));
    r.buyAt+=((Math.random()-.5)*r.buyAt*.0008);r.buyAt=+r.buyAt.toFixed(2);
    r.sellAt=+(r.buyAt*(1+r.spread/100)).toFixed(2);
    positions.forEach(p=>{if(p.sym===r.sym)p.cur=r.buyAt});
  });
  allRows.sort((a,b)=>b.spread-a.spread);
  allRows.forEach((r,i)=>r.rank=i+1);
  applyF();
  document.getElementById('wsLat').textContent=(1+Math.floor(Math.random()*7))+'ms';
  const pnl=positions.reduce((s,p)=>s+(p.side==='LONG'?(p.cur-p.entry)/p.entry*p.qty:(p.entry-p.cur)/p.entry*p.qty),0);
  document.getElementById('totalPnl').textContent='+'+'$'+(280+Math.random()*80+pnl).toFixed(2);
  // win rate
  const closed=tradeHistory.filter(t=>t.status==='closed');
  const wins=closed.filter(t=>t.isWin);
  document.getElementById('winRate').textContent=closed.length?((wins.length/closed.length)*100).toFixed(1)+'%':'—';
  renderPos();
  if(filteredRows[selIdx])renderOB(filteredRows[selIdx].buyAt,filteredRows[selIdx].liq);
  liveBalances();
  updateBalPanel();
}

